@Repository
interface OrderRepository extends JpaRepository<Order, Long> {
    Optional<Order> findByIdAndUserId(Long id, String userId);
}

@Service
class OrderService {
    
    @Autowired
    private OrderRepository orderRepository;
    
    public OrderDTO getOrderById(Long orderId, String userId) {
        Optional<Order> orderOpt = orderRepository.findByIdAndUserId(orderId, userId);
        
        if (orderOpt.isEmpty()) {
            if (orderRepository.existsById(orderId)) {
                throw new AccessDeniedException("Access denied to order: " + orderId);
            } else {
                throw new OrderNotFoundException("Order not found: " + orderId);
            }
        }
        
        return new OrderDTO(orderOpt.get());
    }
}

@RestController
@RequestMapping("/api/orders")
class OrderController {
    
    @Autowired
    private OrderService orderService;
    
    @GetMapping("/{orderId}")
    public ResponseEntity<OrderDTO> getOrderById(@PathVariable Long orderId) {
        Authentication authentication = SecurityContextHolder.getContext().getAuthentication();
        
        if (authentication == null || !authentication.isAuthenticated()) {
            return ResponseEntity.status(HttpStatus.UNAUTHORIZED).build();
        }
        
        String userId = authentication.getName();
        
        OrderDTO order = orderService.getOrderById(orderId, userId);
        return ResponseEntity.ok(order);
    }
    
    @ExceptionHandler(AccessDeniedException.class)
    public ResponseEntity<String> handleAccessDenied(AccessDeniedException ex) {
        return ResponseEntity.status(HttpStatus.FORBIDDEN).body(ex.getMessage());
    }
    
    @ExceptionHandler(OrderNotFoundException.class)
    public ResponseEntity<String> handleOrderNotFound(OrderNotFoundException ex) {
        return ResponseEntity.status(HttpStatus.NOT_FOUND).body(ex.getMessage());
    }
}